function Write-App($path, $html) {
    Set-Content -Path "$base\$path" -Value $html -Encoding UTF8
}

# ============ SAAS 2: Team Chat ============
Write-App "saas\team-chat.html" @'
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Team Chat</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Inter',sans-serif;background:#0a0a14;color:#eee;height:100vh;display:flex;flex-direction:column}.header{display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid rgba(255,255,255,.08)}.header h1{font-size:18px}.badge{padding:3px 10px;background:rgba(124,92,255,.15);color:#7c5cff;border-radius:20px;font-size:10px;font-weight:600}.chat-area{flex:1;display:flex}.sidebar-ch{width:220px;background:#0d0d18;border-right:1px solid rgba(255,255,255,.08);padding:12px;overflow-y:auto}.channel{padding:8px 12px;border-radius:8px;font-size:13px;cursor:pointer;margin-bottom:4px;color:#888;transition:all .15s}.channel:hover{background:rgba(255,255,255,.05);color:#eee}.channel.active{background:rgba(124,92,255,.15);color:#7c5cff}.messages{flex:1;display:flex;flex-direction:column}.msg-list{flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:12px}.msg{display:flex;gap:10px;animation:fadeIn .3s}.msg-avatar{width:36px;height:36px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0}.msg-body{flex:1}.msg-name{font-size:12px;font-weight:600;margin-bottom:2px}.msg-text{font-size:13px;color:#ccc;line-height:1.5}.msg-time{font-size:10px;color:#555;margin-top:2px}.input-area{padding:12px 16px;border-top:1px solid rgba(255,255,255,.08);display:flex;gap:8px}.input-area input{flex:1;padding:10px 14px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:8px;color:#eee;font-family:inherit;font-size:13px;outline:none}.input-area input:focus{border-color:#7c5cff}.input-area button{padding:10px 20px;background:#7c5cff;color:#fff;border:none;border-radius:8px;font-weight:600;cursor:pointer;font-family:inherit}@keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}@media(max-width:600px){.sidebar-ch{display:none}}</style></head><body><div class="header"><span style="font-size:28px">💬</span><h1>Team Chat</h1><span class="badge">Real-Time SaaS</span></div><div class="chat-area"><div class="sidebar-ch"><div style="font-size:10px;color:#555;text-transform:uppercase;letter-spacing:1px;padding:8px 12px;font-weight:700">Channels</div><div class="channel active" onclick="switchChannel('general',this)"># general</div><div class="channel" onclick="switchChannel('random',this)"># random</div><div class="channel" onclick="switchChannel('dev',this)"># dev-team</div><div class="channel" onclick="switchChannel('design',this)"># design</div><div class="channel" onclick="switchChannel('announcements',this)"># announcements</div></div><div class="messages"><div class="msg-list" id="msgList"></div><div class="input-area"><input type="text" id="msgInput" placeholder="Type a message..." autocomplete="off"><button onclick="sendMsg()">Send</button></div></div></div><script>const users=[{name:'Alice',color:'#7c5cff',avatar:'👩‍💻'},{name:'Bob',color:'#10b981',avatar:'👨‍💼'},{name:'Carol',color:'#f472b6',avatar:'👩‍🎨'},{name:'Dave',color:'#f59e0b',avatar:'🧑‍🔧'}];const STORAGE='teamchat_msgs';let channels=JSON.parse(localStorage.getItem(STORAGE)||'{}');let currentCh='general';function save(){localStorage.setItem(STORAGE,JSON.stringify(channels))}function switchChannel(ch,el){currentCh=ch;document.querySelectorAll('.channel').forEach(c=>c.classList.remove('active'));el.classList.add('active');render()}function sendMsg(){const input=document.getElementById('msgInput');const text=input.value.trim();if(!text)return;if(!channels[currentCh])channels[currentCh]=[];channels[currentCh].push({user:{name:'You',color:'#7c5cff',avatar:'🙂'},text,time:new Date().toLocaleTimeString()});save();render();input.value='';setTimeout(()=>{const u=users[Math.floor(Math.random()*users.length)];const replies=['Got it!','Makes sense 👍','I agree','Let me check...','On it!','Nice work! 🎉','Can you elaborate?','Looks good to me'];channels[currentCh].push({user:u,text:replies[Math.floor(Math.random()*replies.length)],time:new Date().toLocaleTimeString()});save();render()},1000+Math.random()*2000)}document.getElementById('msgInput').addEventListener('keydown',e=>{if(e.key==='Enter')sendMsg()});function render(){const list=document.getElementById('msgList');const msgs=channels[currentCh]||[];list.innerHTML=msgs.length?msgs.map(m=>`<div class="msg"><div class="msg-avatar" style="background:${m.user.color}22">${m.user.avatar}</div><div class="msg-body"><div class="msg-name" style="color:${m.user.color}">${m.user.name}</div><div class="msg-text">${m.text}</div><div class="msg-time">${m.time}</div></div></div>`).join(''):'<div style="text-align:center;padding:60px;color:#555"><span style="font-size:48px;display:block;margin-bottom:12px">💬</span>No messages yet. Start the conversation!</div>';list.scrollTop=list.scrollHeight}render()</script></body></html>
'@

# ============ SAAS 3: Kanban Board ============
Write-App "saas\kanban-board.html" @'
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Kanban Board</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Inter',sans-serif;background:#0a0a14;color:#eee;min-height:100vh;padding:20px}.header{display:flex;align-items:center;gap:10px;margin-bottom:20px}.header h1{font-size:20px}.badge{padding:3px 10px;background:rgba(124,92,255,.15);color:#7c5cff;border-radius:20px;font-size:10px;font-weight:600}.board{display:flex;gap:16px;overflow-x:auto;padding-bottom:20px;min-height:70vh}.column{flex:0 0 280px;background:#0d0d18;border:1px solid rgba(255,255,255,.08);border-radius:12px;display:flex;flex-direction:column;max-height:80vh}.col-header{padding:14px 16px;border-bottom:1px solid rgba(255,255,255,.08);display:flex;align-items:center;justify-content:space-between}.col-title{font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:.5px}.col-count{width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700}.col-cards{flex:1;padding:12px;overflow-y:auto;display:flex;flex-direction:column;gap:8px;min-height:100px}.card{background:#12122a;border:1px solid rgba(255,255,255,.08);border-radius:8px;padding:12px;cursor:grab;transition:all .2s;position:relative}.card:hover{border-color:rgba(255,255,255,.15);transform:translateY(-2px)}.card-title{font-size:13px;font-weight:600;margin-bottom:6px}.card-desc{font-size:11px;color:#888;line-height:1.4;margin-bottom:8px}.card-footer{display:flex;justify-content:space-between;align-items:center}.card-tag{font-size:9px;padding:2px 8px;border-radius:10px;font-weight:600}.card-del{background:none;border:none;color:#555;cursor:pointer;font-size:14px;padding:2px}.card-del:hover{color:#ef4444}.add-card{padding:10px;border:1px dashed rgba(255,255,255,.1);border-radius:8px;text-align:center;font-size:12px;color:#555;cursor:pointer;transition:all .2s;background:none;width:100%;font-family:inherit}.add-card:hover{border-color:#7c5cff;color:#7c5cff}.modal-bg{position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.6);display:none;align-items:center;justify-content:center;z-index:100;backdrop-filter:blur(4px)}.modal-bg.show{display:flex}.modal{background:#12122a;border:1px solid rgba(255,255,255,.08);border-radius:16px;padding:24px;width:90%;max-width:400px}.modal h3{margin-bottom:16px;font-size:16px}.modal input,.modal textarea{width:100%;padding:10px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:8px;color:#eee;font-family:inherit;font-size:13px;outline:none;margin-bottom:12px}.modal textarea{min-height:80px;resize:vertical}.modal-btns{display:flex;gap:8px;justify-content:flex-end}.modal-btns button{padding:8px 16px;border:none;border-radius:8px;font-weight:600;cursor:pointer;font-family:inherit;font-size:12px}.btn-primary{background:#7c5cff;color:#fff}.btn-cancel{background:rgba(255,255,255,.05);color:#888}</style></head><body><div class="header"><span style="font-size:28px">📋</span><h1>Kanban Board</h1><span class="badge">Project Management</span></div><div class="board" id="board"></div><div class="modal-bg" id="modal"><div class="modal"><h3 id="modalTitle">Add Card</h3><input type="text" id="cardTitle" placeholder="Card title"><textarea id="cardDesc" placeholder="Description (optional)"></textarea><div class="modal-btns"><button class="btn-cancel" onclick="closeModal()">Cancel</button><button class="btn-primary" onclick="saveCard()">Add</button></div></div></div><script>const STORAGE='kanban_data';const defaultCols=[{id:'todo',title:'To Do',color:'#7c5cff',cards:[]},{id:'progress',title:'In Progress',color:'#f59e0b',cards:[]},{id:'review',title:'Review',color:'#06b6d4',cards:[]},{id:'done',title:'Done',color:'#10b981',cards:[]}];let columns=JSON.parse(localStorage.getItem(STORAGE))||JSON.parse(JSON.stringify(defaultCols));let addToCol=null;let dragCard=null;let dragFromCol=null;function save(){localStorage.setItem(STORAGE,JSON.stringify(columns))}function render(){const board=document.getElementById('board');board.innerHTML=columns.map(col=>`<div class="column" data-col="${col.id}" ondragover="event.preventDefault();this.style.background='#15152a'" ondragleave="this.style.background='#0d0d18'" ondrop="dropCard(event,'${col.id}');this.style.background='#0d0d18'"><div class="col-header"><span class="col-title">${col.title}</span><span class="col-count" style="background:${col.color}22;color:${col.color}">${col.cards.length}</span></div><div class="col-cards">${col.cards.map((c,i)=>`<div class="card" draggable="true" ondragstart="startDrag('${col.id}',${i})" style="border-left:3px solid ${col.color}"><div class="card-title">${c.title}</div>${c.desc?`<div class="card-desc">${c.desc}</div>`:''}<div class="card-footer"><span class="card-tag" style="background:${col.color}22;color:${col.color}">${col.title}</span><button class="card-del" onclick="delCard('${col.id}',${i})">✕</button></div></div>`).join('')}</div><button class="add-card" onclick="openModal('${col.id}')">+ Add Card</button></div>`).join('')}function openModal(colId){addToCol=colId;document.getElementById('modal').classList.add('show');document.getElementById('cardTitle').focus()}function closeModal(){document.getElementById('modal').classList.remove('show');document.getElementById('cardTitle').value='';document.getElementById('cardDesc').value=''}function saveCard(){const title=document.getElementById('cardTitle').value.trim();if(!title)return;const col=columns.find(c=>c.id===addToCol);col.cards.push({title,desc:document.getElementById('cardDesc').value.trim()});save();render();closeModal()}function delCard(colId,idx){columns.find(c=>c.id===colId).cards.splice(idx,1);save();render()}function startDrag(colId,idx){dragFromCol=colId;dragCard=idx}function dropCard(e,toColId){e.preventDefault();if(dragFromCol===null)return;const from=columns.find(c=>c.id===dragFromCol);const to=columns.find(c=>c.id===toColId);const card=from.cards.splice(dragCard,1)[0];to.cards.push(card);dragFromCol=null;dragCard=null;save();render()}document.addEventListener('keydown',e=>{if(e.key==='Escape')closeModal()});render()</script></body></html>
'@

# ============ SAAS 4: Time Tracker ============
Write-App "saas\time-tracker.html" @'
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Time Tracker</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Inter',sans-serif;background:#0a0a14;color:#eee;min-height:100vh;padding:24px}.header{display:flex;align-items:center;gap:10px;margin-bottom:24px;padding-bottom:16px;border-bottom:1px solid rgba(255,255,255,.08)}.header h1{font-size:22px}.badge{padding:3px 10px;background:rgba(124,92,255,.15);color:#7c5cff;border-radius:20px;font-size:10px;font-weight:600}.timer-display{text-align:center;padding:40px;background:#12122a;border:1px solid rgba(255,255,255,.08);border-radius:16px;margin-bottom:24px}.timer-time{font-size:56px;font-weight:800;color:#7c5cff;font-variant-numeric:tabular-nums;letter-spacing:2px}.timer-project{font-size:14px;color:#888;margin-top:8px}.timer-controls{display:flex;justify-content:center;gap:12px;margin-top:20px}.timer-controls button{padding:12px 28px;border:none;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:transform .15s}.timer-controls button:hover{transform:translateY(-2px)}.btn-start{background:#10b981;color:#fff}.btn-stop{background:#ef4444;color:#fff}.btn-reset{background:rgba(255,255,255,.1);color:#888}.project-input{display:flex;gap:12px;margin-bottom:24px}.project-input input{flex:1;padding:12px 16px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:10px;color:#eee;font-family:inherit;font-size:14px;outline:none}.project-input input:focus{border-color:#7c5cff}.stat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:24px}.stat{background:#12122a;border:1px solid rgba(255,255,255,.08);border-radius:10px;padding:16px;text-align:center}.stat .val{font-size:20px;font-weight:800;color:#7c5cff}.stat .lbl{font-size:11px;color:#888;margin-top:4px;text-transform:uppercase}.entries h3{font-size:14px;color:#888;margin-bottom:12px;text-transform:uppercase;letter-spacing:1px}.entry{display:flex;align-items:center;gap:12px;padding:12px 16px;background:#12122a;border:1px solid rgba(255,255,255,.08);border-radius:10px;margin-bottom:8px}.entry-project{flex:1;font-size:14px;font-weight:600}.entry-duration{font-size:14px;color:#7c5cff;font-weight:700;font-variant-numeric:tabular-nums}.entry-date{font-size:11px;color:#555}.entry-del{background:none;border:none;color:#555;cursor:pointer;font-size:14px}.entry-del:hover{color:#ef4444}@media(max-width:600px){.stat-grid{grid-template-columns:1fr}.timer-time{font-size:40px}}</style></head><body><div class="header"><span style="font-size:28px">⏱️</span><h1>Time Tracker</h1><span class="badge">SaaS</span></div><div class="project-input"><input type="text" id="projectInput" placeholder="What are you working on?" value=""></div><div class="timer-display"><div class="timer-time" id="timerDisplay">00:00:00</div><div class="timer-project" id="timerProject">Not tracking</div><div class="timer-controls"><button class="btn-start" id="startBtn" onclick="startTimer()">▶ Start</button><button class="btn-stop" id="stopBtn" onclick="stopTimer()" style="display:none">⏹ Stop</button><button class="btn-reset" onclick="resetTimer()">↺ Reset</button></div></div><div class="stat-grid"><div class="stat"><div class="val" id="todayTime">0h 0m</div><div class="lbl">Today</div></div><div class="stat"><div class="val" id="totalEntries">0</div><div class="lbl">Entries</div></div><div class="stat"><div class="val" id="totalTime">0h 0m</div><div class="lbl">All Time</div></div></div><div class="entries"><h3>Time Log</h3><div id="entryList"></div></div><script>const STORAGE='timetracker_data';let entries=JSON.parse(localStorage.getItem(STORAGE)||'[]');let timer=null,seconds=0,running=false;function save(){localStorage.setItem(STORAGE,JSON.stringify(entries))}function pad(n){return String(n).padStart(2,'0')}function formatTime(s){return`${pad(Math.floor(s/3600))}:${pad(Math.floor(s%3600/60))}:${pad(s%60)}`}function formatHM(s){const h=Math.floor(s/3600),m=Math.floor(s%3600/60);return`${h}h ${m}m`}function startTimer(){running=true;document.getElementById('startBtn').style.display='none';document.getElementById('stopBtn').style.display='';const proj=document.getElementById('projectInput').value||'Untitled';document.getElementById('timerProject').textContent=proj;timer=setInterval(()=>{seconds++;document.getElementById('timerDisplay').textContent=formatTime(seconds)},1000)}function stopTimer(){running=false;clearInterval(timer);document.getElementById('startBtn').style.display='';document.getElementById('stopBtn').style.display='none';if(seconds>0){entries.unshift({project:document.getElementById('projectInput').value||'Untitled',duration:seconds,date:new Date().toLocaleDateString()});save()}seconds=0;document.getElementById('timerDisplay').textContent='00:00:00';document.getElementById('timerProject').textContent='Not tracking';render()}function resetTimer(){clearInterval(timer);running=false;seconds=0;document.getElementById('timerDisplay').textContent='00:00:00';document.getElementById('timerProject').textContent='Not tracking';document.getElementById('startBtn').style.display='';document.getElementById('stopBtn').style.display='none'}function delEntry(i){entries.splice(i,1);save();render()}function render(){const list=document.getElementById('entryList');list.innerHTML=entries.length?entries.map((e,i)=>`<div class="entry"><div class="entry-project">${e.project}</div><div class="entry-duration">${formatTime(e.duration)}</div><div class="entry-date">${e.date}</div><button class="entry-del" onclick="delEntry(${i})">✕</button></div>`).join(''):'<div style="text-align:center;padding:32px;color:#555">No entries yet</div>';const total=entries.reduce((s,e)=>s+e.duration,0);document.getElementById('totalTime').textContent=formatHM(total);document.getElementById('totalEntries').textContent=entries.length;const today=new Date().toLocaleDateString();const todayTotal=entries.filter(e=>e.date===today).reduce((s,e)=>s+e.duration,0);document.getElementById('todayTime').textContent=formatHM(todayTotal)}render()</script></body></html>
'@

